INSERT INTO price_snapshots (
  part_id,
  price,
  source,
  collected_at,
  raw_payload
)
SELECT p.id,
       p.price,
       'MANUAL_CURRENT_LINEUP',
       '2026-06-29T13:50:00Z',
       jsonb_build_object(
         'source', 'manual-current-lineup',
         'collector', 'prototype-seed',
         'catalogGeneration', 'CURRENT_2026_06',
         'partPublicId', p.public_id::text,
         'keyword', coalesce(p.attributes #>> '{externalSources,danawa,keyword}', p.name),
         'backupOnly', true,
         'shippingIncluded', false,
         'couponIncluded', false
       )
FROM parts p
WHERE p.id BETWEEN 11001 AND 11606;

